<script lang="ts" setup>
const props = defineProps<{
  icon?: string
  spinner?: string
  loading?: boolean
  onClick?: () => any | Promise<any>
}>()

const isResolving = ref(false)

async function handleClick() {
  const fn = props.onClick

  if (!fn)
    return

  isResolving.value = true
  await fn()
  isResolving.value = false
}
</script>

<template>
  <button
    class="flex-center active:scale-97 disabled:opacity-70 transition-transform"
    :inert="loading || isResolving"
    @click="handleClick"
  >
    <Spinner v-if="loading || isResolving" size="xs" :class="spinner" />
    <span v-else-if="icon" class="inline-block" :class="icon" />
  </button>
</template>
