<script lang="ts" setup>
import type { Nullable } from '@antfu/utils'

defineOptions({
  inheritAttrs: false
})

const props = defineProps<{
  onSave: (value: string) => Promise<any> | any
}>()

const modelValue = defineModel<Nullable<string>>()
const localValue = defineModel<Nullable<string>>('session')

async function handleSave() {
  const value = localValue.value ?? ''

  await props.onSave(value)
  modelValue.value = value
}

onBeforeMount(() => {
  localValue.value = modelValue.value
})
</script>

<template>
  <div class="grow relative min-h-150px">
    <textarea
      v-model="localValue"
      class="absolute inset-0 resize-none w-full p-4 rounded-md bg-hex-F7F7F7 text-sm placeholder:text-neutral/70"
      v-bind="$attrs"
    />

    <Transition name="fade">
      <CTAButton v-if="modelValue !== localValue" class="absolute bottom-5 right-5 min-w-100px flex-center text-13px font-medium bg-black text-white" @click="handleSave">
        Save
      </CTAButton>
    </Transition>
  </div>
</template>
