<script lang="ts" setup>
const user = useUser()

const appsumo = computed(() => {
  const data = user.appsumo
  const { count = 0, plan = 0 } = data ?? {}

  return {
    active: !!data,
    count,
    plan,
    progress: 1 - (count / plan)
  }
})
</script>

<template>
  <div v-if="appsumo.active" class="settings-card text-13px flex gap-3 items-center">
    <img
      src="https://appsumo2-cdn.appsumo.com/static/images/favicon.svg"
      alt=""
      loading="lazy"
      height="24"
      class="h-24px"
    >

    <div class="flex-grow">
      <h3>
        Appsumo
      </h3>

      <span class="opacity-60 font-light">
        You have drafted {{ appsumo.count }} out of {{ appsumo.plan }} emails this month
      </span>

      <div class="relative overflow-hidden h-3px mt-1 w-full rounded-full bg-black/5 after:content-[''] after:absolute after:size-full after:bg-primary after:translate-x-$value" :style="{ '--value': `calc(-100% * ${appsumo.progress})` }" />
    </div>
  </div>

  <div v-else-if="!user.subscribed" class="settings-card upgrade-card relative">
    <!-- Effects -->
    <div class="pointer-events-none">
      <img src="@/assets/images/inbox.svg" alt="" class="absolute bottom-2 right-[28%] rotate-15">
      <img src="@/assets/images/star.svg" alt="" class="absolute -top-3 right-[30%] rotate-30">
      <img src="@/assets/images/star.svg" alt="" class="absolute -bottom-5 right-3 rotate-20">
    </div>

    <div class="relative flex items-center justify-between">
      <h2 class="max-w-315px text-sm font-light">
        Auto Gmail on mobile. Instants drafts.<br>
        Smarter Emails. Unlimited email generation!
      </h2>

      <CTAButton variant="primary" class="flex-shrink-0 text-13px font-semibold" @click="user.openPaymentPage">
        Upgrade Now
      </CTAButton>
    </div>
  </div>

  <div v-else-if="!user.connected" class="settings-card relative flex items-center justify-between">
    <h2 class="max-w-230px text-sm font-light">
      Please connect your gmail account to use the pro features
    </h2>

    <CTAButton
      variant="neutral"
      icon="i-logos:google-icon"
      class="flex-shrink-0 text-13px"
      @click="user.connectGmail"
    >
      Connect Gmail
    </CTAButton>
  </div>

  <div v-else-if="user.connected" class="text-right text-13px font-light">
    <template v-if="user.connection_error">
      Your Gmail account was disconnected —
      <button class="text-primary font-normal" @click="user.connectGmail">
        reconnect
      </button>
    </template>

    <template v-else>
      Your gmail account is <span class="text-primary font-normal">connected</span>
    </template>
  </div>
</template>

<style scoped lang="sass">
.upgrade-card
  background-image: linear-gradient(to right, rgba(255, 116, 56, 0.35), transparent 45%)
</style>
