<script lang="ts" setup>
import Editor from './SettingsTextEditor.vue'

const user = useUser()
const { isLoading: isRemovingTip, refresh: removeTip } = usePromise(false, async (index: number) => {
  // Clone source to avoid sync updates
  const tips = Array.from(user.ai_tips)

  tips.splice(index, 1)
  return user.updateContext(user.context, tips)
})
</script>

<template>
  <div>
    <!-- AI Tips -->
    <div v-if="user.ai_tips.length" class="p-4 mb-4 rounded-md border-1 border-neutral/8 [&[inert]]:opacity-80" :inert="isRemovingTip">
      <h3 class="mb-2 gap-2 flex items-center text-sm">
        <span class="i-streamline:brain-cognitive-solid inline-block size-4 text-primary/70" />
        Here's what the AI learned from you:
      </h3>

      <section class="max-h-30vh overflow-hidden overflow-y-auto">
        <div
          v-for="(tip, i) in user.ai_tips"
          :key="i"
          class="group h-36px py-1 flex items-center text-13px text-neutral/70 hover:px-3 hover:bg-#fafafa cursor-default"
        >
          {{ tip }}

          <IconButton
            icon="i-mdi-close size-4 text-neutral/30 group-not-hover:hidden"
            class="ml-auto"
            @click="removeTip(i)"
          />
        </div>
      </section>
    </div>

    <h3 class="mb-3 text-13px font-light">
      Give your AI context what it should know and on how to respond.
    </h3>

    <Editor
      v-model="user.context"
      class="p-4"
      placeholder="Write smart, short, concise, pragmatic and useful responses. Make sure to answer in the language of the person who sent the email. Write in plain text (no markdown / html)"
      @save="user.updateContext"
    />
  </div>
</template>
