<script lang="tsx" setup>
const user = useUser()
const settings = useSettings()

const Card = defineComponent({
  props: {
    title: String,
    description: String,
    isFree: {
      type: Boolean,
      default: false
    }
  },

  setup(props, ctx) {
    return () => (
      <div class="settings-card group relative text-sm leading-normal break-keep">
        <div class="mb-6px gap-3 flex items-center justify-between">
          {props.title}
          {ctx.slots.default?.()}
        </div>

        <span class="font-light tracking-[1%] opacity-80">
          {props.description}
        </span>

        {!props.isFree && !user.subscribed && (
          <div class="upgrade-card-shadow absolute inset-0 px-4 flex-center bg-white/4 backdrop-blur-2 group-not-hover:opacity-0 group-not-hover:scale-95 transition active:scale-96">
            <button class="px-6 py-4 rounded-5px bg-white text-sm" onClick={user.openPaymentPage}>
              Upgrade to unlock
            </button>
          </div>
        )}
      </div>
    )
  }
})
</script>

<template>
  <div class="w-full gap-3 grid grid-cols-2 break-all">
    <template v-if="!user.appsumo">
      <Card title="Generate Smarter Emails" description="Import past emails for context. This improves AI responses.">
        <Switch disabled :model-value="user.connected" />
      </Card>

      <Card title="Auto Generate Emails" description="Generate emails while away. Enable Auto Gmail on mobile.">
        <Switch :model-value="user.enabled" @update="user.toggleAI" />
      </Card>
    </template>

    <Card
      is-free
      title="Auto Draft Emails"
      description="Draft email replies automatically when you click 'Reply'"
      class="col-span-2"
    >
      <Switch v-model="settings.autoDraft" />
    </Card>
  </div>
</template>

<style scoped lang="sass">
.upgrade-card-shadow
  box-shadow: 0 0 4px 1px rgba(0, 0, 0, 0.06), 4px 4px 2px 0px rgba(0, 0, 0, 0.06)
</style>
